MODE_RANK = {"risk_off": "risk off", "neutral": "neutral", "risk_on": "risk on"}


def _now_str():
    return dt.datetime.now().strftime("%a %d %b, %H:%M")


def _sh(x):
    """Format a share quantity: whole → '42', fractional → '2.35' (no trailing 0s)."""
    try:
        x = float(x)
    except (TypeError, ValueError):
        return str(x)
    if abs(x - round(x)) < 1e-9:
        return str(int(round(x)))
    return ("{:.4f}".format(x)).rstrip("0").rstrip(".")


_FX_RATE = 0.74     # GBP per USD; refreshed by _fx_rate() at each generate()


def _fx_rate():
    """GBP-per-USD display rate (the bot TRADES in USD; the account is GBP).
    Shared logic lives in bot.fx so broker_sync uses the identical rate."""
    global _FX_RATE
    from bot import fx
    _FX_RATE = fx.gbp_per_usd()
    return _FX_RATE


def _gbp(v_usd):
    """USD account value -> GBP display value."""
    return (v_usd or 0) * _FX_RATE


def _money(v, sign=False):
    """Compact GBP display of a USD value: £8.0k, £1.2M, £940, −£3.7k.
    Account VALUES show in £ (Josh's currency); per-share PRICES stay in $
    (the currency they actually trade in)."""
    v = _gbp(v)
    s = "+" if (sign and v >= 0) else ("−" if v < 0 else "")
    a = abs(v)
    if a >= 1_000_000:
        body = "£{:.2f}M".format(a / 1_000_000)
    elif a >= 10_000:
        body = "£{:.1f}k".format(a / 1000)
    elif a >= 1_000:
        body = "£{:,.0f}".format(a)
    else:
        body = "£{:,.2f}".format(a)
    return s + body


def _load_health():
    """Workflow run statuses written by the scan workflow, or {}."""
    p = os.path.join(ROOT, "data", "health.json")
    if os.path.exists(p):
        try:
            with open(p) as f:
                return json.load(f)
        except Exception:
            return {}
    return {}


def _short(ts):
    return ts[5:16].replace("T", " ") if ts else "—"


def panel(title, asof, inner, extra=""):
    return ('<div class="panel"{x}><div class="ph"><h2>{t}</h2>'
            '<span class="asof">as of {a}</span></div>{i}</div>').format(
        t=title, a=asof, i=inner, x=extra)


