def _sched_script():
    """Live countdown to next scan/intel/research, computed in the viewer's
    local time from the known UTC cron schedules."""
    return """
<script>
(function(){
  // UTC schedules (min past hour, UTC hours, allowed weekdays 0=Sun..6=Sat)
  var WD=[1,2,3,4,5];
  var SCANS={min:33,hours:[13,14,15,16,17,18,19,20,21],days:WD};
  var INTEL={min:8,hours:[14,15,16,17,18,19,20],days:WD};
  var RESEARCH={min:37,hours:[12],days:WD};
  var REVIEW={min:3,hours:[16],days:[0]};
  // maps the "Running on GitHub" rows (nr-<key>) to their schedule
  var WORKFLOWS={"trading-scan":SCANS,"hourly-intel":INTEL,
                 "daily-research":RESEARCH,"weekly-review":REVIEW,"backtest":null};
  function nextRun(s){
    if(!s)return null;
    var days=s.days||WD;var now=new Date();
    for(var d=0;d<8;d++){
      var day=new Date(now.getTime()+d*86400000);
      if(days.indexOf(day.getUTCDay())<0)continue;
      for(var i=0;i<s.hours.length;i++){
        var t=new Date(Date.UTC(day.getUTCFullYear(),day.getUTCMonth(),day.getUTCDate(),s.hours[i],s.min,0));
        if(t>now)return t;
      }
    }
    return null;
  }
  function fmt(ms){
    if(ms<0)return"now";
    var m=Math.floor(ms/60000),h=Math.floor(m/60);m=m%60;
    if(h>0)return h+"h "+m+"m";
    var sec=Math.floor((ms%60000)/1000);
    return m+"m "+String(sec).padStart(2,"0")+"s";
  }
  function marketOpen(){
    var n=new Date(),h=n.getUTCHours(),day=n.getUTCDay();
    if(day===0||day===6)return false;
    var mins=h*60+n.getUTCMinutes();
    return mins>=13*60+30&&mins<20*60;  // ~9:30-16:00 ET in UTC (summer)
  }
  function tick(){
    var now=new Date();
    var defs=[["scan-next",SCANS],["intel-next",INTEL],["research-next",RESEARCH]];
    defs.forEach(function(d){
      var el=document.getElementById(d[0]);if(!el)return;
      var nx=nextRun(d[1]);if(!nx){el.textContent="—";return;}
      var ms=nx-now;el.textContent="in "+fmt(ms);
      el.className="sv"+(ms<120000?" now":(ms<600000?" soon":""));
    });
    // next-run countdown next to each workflow row in "Running on GitHub"
    Object.keys(WORKFLOWS).forEach(function(k){
      var el=document.getElementById("nr-"+k);if(!el)return;
      var s=WORKFLOWS[k];
      if(!s){el.textContent="on demand";return;}
      var nx=nextRun(s);
      if(nx){var ms=nx-now;el.textContent="in "+fmt(ms);
        el.style.color=ms<300000?"var(--teal)":"var(--dim)";}
    });
    var dot=document.getElementById("scandot");
    var open=marketOpen();
    if(dot)dot.className="dot"+(open?"":" closed");
    // WSB-style market countdown — rotates every minute
    var OPEN_MSGS=[
      "🔔 market's OPEN — the casino is live 🎰",
      "🚀 bell's rung, let the tendies flow",
      "📈 stonks only go up (this is not financial advice, it's a vibe)",
      "💎🙌 diamond hands engaged, positions armed",
      "🖍 crayons eaten, orders placed",
      "sir, this is a casino — and it's open",
      "⏰ prime tendie-harvesting hours",
      "the floor is open. so is the ceiling. statistically, mostly the floor.",
      "buy high, sell low — wait. hang on. other way round",
      "your wife's boyfriend wishes you luck out there",
      "📊 charts are moving. nobody knows why. proceeding anyway",
      "risk management? never met her. (the bot has — 8% stops armed)",
      "it's not a loss until you sell. (the bot WILL sell. that's the point.)",
      "nothing is ever priced in",
      "no GUH moments yet today — the day is young",
      "the algorithm hungers. feed it volume 🦾",
      "may your spreads be tight and your fills be kind 🙏",
      "🦍 apes together strong. bot ape strongest.",
      "loss porn averted so far. stay tuned.",
      "turning insider filings into tendies since 2026"];
    var PRE_MSGS=[
      "hydrate, stretch, sharpen a crayon 🖍",
      "DD is just vibes with extra charts",
      "futures are moving — so obviously the open will do the opposite",
      "pre-market jitters intensify 😰",
      "setting phasers to BUY (pending confluence)",
      "the tendie oven is preheating 🍗",
      "scared money don't make money. it also don't lose money. choose wisely.",
      "insider filings read. gates armed. bring the bell. 🔔"];
    var EVE_MSGS=[
      "🔕 closed — the casino sleeps, the bags hold themselves",
      "closed. loss porn processing overnight 🖨",
      "after hours: where good news goes to get faded",
      "the bot is studying. you should sleep. 📚",
      "tendies secured? check the Halls 🏆🤡",
      "overnight learnings brewing ☕ — smarter by morning",
      "closed — tomorrow we ride at 9:30 sharp 🚀",
      "positions tucked in. stops set. goodnight, anon 🌙"];
    var WKND_MSGS=[
      "🛌 weekend — market closed. go touch grass, anon",
      "the only two days stonks can't hurt you",
      "weekend: practice your gain-porn screenshots (manifesting)",
      "closed till Monday — the bot dreams of green candles 💤",
      "no charts, no tears. weekend vibes 🌴",
      "even the algorithm takes weekends off (the learnings don't)"];
    function pick(a){return a[Math.floor(now.getTime()/60000)%a.length];}
    var mkt=document.getElementById("mkt");
    if(mkt){
      if(open){
        mkt.className="mkt open";
        mkt.textContent=pick(OPEN_MSGS);
      }else{
        var openDef={min:30,hours:[13,14]}; // 9:30 ET summer/winter in UTC
        var nx=nextRun(openDef);
        var dow=now.getUTCDay();
        if(dow===0||dow===6){
          mkt.className="mkt";
          mkt.textContent=pick(WKND_MSGS);
        }else if(nx){
          var ms=nx-now;
          mkt.className="mkt";
          // within 3h of open = pre-market flavour; otherwise evening flavour
          mkt.textContent=(ms<10800000)
            ? "⏰ opens in "+fmt(ms)+" — "+pick(PRE_MSGS)
            : pick(EVE_MSGS)+" · opens in "+fmt(ms);
        }
      }
    }
    // progress bar = fraction through the current hour toward next scan
    var bar=document.getElementById("hourbar");
    if(bar){var nx=nextRun(SCANS);if(nx){var frac=1-((nx-now)/3600000);
      frac=Math.max(0,Math.min(1,frac));bar.style.width=(frac*100).toFixed(1)+"%";}}
  }
  tick();setInterval(tick,1000);
})();
</script>"""


PRICES_URL = "https://raw.githubusercontent.com/TheJiveAlive/trading-bot/main/data/prices.json"


_LIVE_WORKER = ""   # set from config.live_quote_url in generate()


def _live_ticker(cost_basis):
    """Live-updating ticker tape: polls prices.json (CORS-enabled raw URL) every
    45s and shows held positions with live price + P/L%. cost_basis: {tkr: avg}.
    Renders nothing when the book is flat — no ghosts of former positions."""
    if not cost_basis:
        return ""
    import json as _json
    return """
<style>
.livewrap{max-width:1140px;margin:8px auto 0;padding:0 20px;}
.live{display:flex;align-items:center;gap:14px;flex-wrap:wrap;padding:8px 14px;
  border:1px solid var(--line);border-radius:10px;background:linear-gradient(160deg,#0b1420,#080d16);
  font-family:ui-monospace,Menlo,monospace;font-size:12.5px;overflow-x:auto;}
.live .ld{width:8px;height:8px;border-radius:50%;background:var(--gain);
  animation:pulse 1.6s infinite;flex:none;}
.live .lbl{color:var(--dim);font-size:9.5px;font-weight:800;letter-spacing:1.4px;text-transform:uppercase;flex:none;}
.live .q{display:flex;gap:6px;align-items:baseline;white-space:nowrap;}
.live .q .t{color:var(--violet);font-weight:700;}
.live .q .p{color:var(--ink);}
.live .q .c.up{color:var(--gain);} .live .q .c.dn{color:var(--loss);}
.live .ago{margin-left:auto;color:var(--dim);font-size:10px;flex:none;}
.live .flash{transition:background .1s;}
.live .flash.f{background:rgba(78,209,197,.18);border-radius:3px;}
</style>
<div class="livewrap"><div class="live" id="live">
  <span class="ld" id="lived"></span><span class="lbl">Live</span>
  <span id="livequotes" style="display:flex;gap:16px;flex-wrap:wrap;">connecting…</span>
  <span class="ago" id="liveago"></span>
</div></div>
<script>
(function(){
  var COST=""" + _json.dumps(cost_basis) + """;
  var URL=\"""" + PRICES_URL + """\";
  var last={};
  function render(data){
    var box=document.getElementById("livequotes");
    var px=data.prices||{};
    var held=data.held||Object.keys(COST);
    if(!held.length){box.textContent="flat — no live positions";return;}
    var html="";
    held.forEach(function(t){
      var p=px[t]; if(p==null)return;
      var cost=COST[t];
      var pct=cost?((p/cost-1)*100):null;
      var cls=pct==null?"":(pct>=0?"up":"dn");
      var flash=(last[t]!=null&&last[t]!==p)?"flash f":"flash";
      html+='<span class="q '+flash+'"><span class="t">'+t+'</span>'+
        '<span class="p">$'+p.toFixed(p<1?3:2)+'</span>'+
        (pct==null?'':'<span class="c '+cls+'">'+(pct>=0?"+":"")+pct.toFixed(1)+'%</span>')+'</span>';
      last[t]=p;
    });
    box.innerHTML=html||"waiting for quotes…";
    setTimeout(function(){document.querySelectorAll(".live .q.f").forEach(function(e){e.classList.remove("f");});},150);
    var gen=data.generated?new Date(data.generated):null;
    var ago=document.getElementById("liveago");
    // is the US market open right now? (13:30-20:00 UTC weekdays)
    var n=new Date(),mins=n.getUTCHours()*60+n.getUTCMinutes(),dow=n.getUTCDay();
    var open=(dow>=1&&dow<=5&&mins>=810&&mins<1200);
    var s=gen?Math.round((Date.now()-gen)/1000):99999;
    if(ago){
      if(!open){ago.textContent="● MARKET CLOSED — showing last close";ago.style.color="var(--dim)";}
      else{ago.textContent="● LIVE · "+(data.source||"")+" · "+(s<90?s+"s":Math.round(s/60)+"m")+" ago";
        ago.style.color=s<330?"var(--gain)":"var(--warn)";}
    }
    document.getElementById("lived").style.background=(open&&s<600)?"var(--gain)":"var(--dim)";
  }
  var WORKER=\"""" + _LIVE_WORKER + """\";
  function poll(){
    var syms=Object.keys(COST);
    var u=WORKER?(WORKER+"?symbols="+syms.join(",")):(URL+"?t="+Date.now());
    fetch(u,{cache:"no-store"}).then(function(r){return r.json();}).then(function(d){
      if(WORKER)d.held=syms;   // worker returns only prices; supply held list
      render(d);
    }).catch(function(){
      document.getElementById("lived").style.background="var(--loss)";
    });
  }
  poll();setInterval(poll,WORKER?20000:30000);
})();
</script>"""


def _fx_script(mood):
    """Ambient weather: gold coins rain when up, rain when down, calm when flat.
    Honors prefers-reduced-motion (renders nothing)."""
    return """
<style>#fx{position:fixed;inset:0;width:100vw;height:100vh;pointer-events:none;
z-index:1;opacity:.3}@media (prefers-reduced-motion:reduce){#fx{display:none}}</style>
<script>
(function(){
  var MOOD=""" + '"' + mood + '"' + """;
  if(MOOD==="flat")return;
  var m=window.matchMedia("(prefers-reduced-motion:reduce)");
  if(m.matches)return;
  var c=document.getElementById("fx"),x=c.getContext("2d"),W,H,P=[];
  function size(){W=c.width=innerWidth;H=c.height=innerHeight;}
  size();addEventListener("resize",size);
  var UP=MOOD==="up";
  // subtle: a light drift, not a downpour
  var N=UP?Math.min(14,Math.floor(W/110)):Math.min(40,Math.floor(W/40));
  function coin(){return{x:Math.random()*W,y:Math.random()*-H,r:3.5+Math.random()*3.5,
    vy:0.6+Math.random()*0.9,sp:Math.random()*Math.PI,vs:0.03+Math.random()*0.06,
    sway:Math.random()*0.4};}
  function drop(){return{x:Math.random()*W,y:Math.random()*-H,len:7+Math.random()*10,
    vy:3.5+Math.random()*3.5,vx:-0.8};}
  for(var i=0;i<N;i++)P.push(UP?coin():drop());
  function draw(){
    x.clearRect(0,0,W,H);
    for(var i=0;i<P.length;i++){var p=P[i];
      if(UP){
        p.y+=p.vy;p.sp+=p.vs;p.x+=Math.sin(p.sp)*p.sway;
        var w=Math.abs(Math.cos(p.sp))*p.r+1.5;
        var g=x.createLinearGradient(p.x-w,p.y-p.r,p.x+w,p.y+p.r);
        g.addColorStop(0,"#FFE9A3");g.addColorStop(.5,"#F5C542");g.addColorStop(1,"#B8860B");
        x.beginPath();x.ellipse(p.x,p.y,w,p.r,0,0,7);x.fillStyle=g;x.fill();
        x.strokeStyle="rgba(120,80,0,.5)";x.lineWidth=1;x.stroke();
        if(w>p.r*0.55){x.fillStyle="rgba(120,80,0,.75)";x.font="bold "+(p.r)+"px ui-monospace,monospace";
          x.textAlign="center";x.textBaseline="middle";x.fillText("$",p.x,p.y+0.5);}
        if(p.y>H+p.r){P[i]=coin();P[i].y=-p.r;}
      }else{
        p.y+=p.vy;p.x+=p.vx;
        x.beginPath();x.moveTo(p.x,p.y);x.lineTo(p.x+p.vx*1.5,p.y+p.len);
        x.strokeStyle="rgba(120,160,220,.2)";x.lineWidth=1;x.stroke();
        if(p.y>H){P[i]=drop();P[i].y=-p.len;}
      }
    }
    requestAnimationFrame(draw);
  }
  draw();
})();
</script>"""


# ---------------- data ----------------

def _realized_trades(trades_asc):
    """Pair sells with running cost basis -> list of closed-trade dicts."""
    book, closed = {}, []
    for ts, side, t, sh, price, value, mode, reason in trades_asc:
        if side == "buy":
            cur = book.get(t, (0, 0.0))
            n = cur[0] + sh
            book[t] = (n, (cur[0] * cur[1] + sh * price) / n if n else 0.0)
        else:
            n, avg = book.get(t, (0, price))
            pnl = (price - avg) * sh
            closed.append({"ts": ts, "ticker": t, "shares": sh, "buy": avg,
                           "sell": price, "pnl": pnl,
                           "pct": (price / avg - 1) * 100 if avg else 0,
                           "reason": (reason or "").split(";")[0][:60]})
            left = n - sh
            if left > 0:
                book[t] = (left, avg)
            else:
                book.pop(t, None)
    return closed


def _fetch_state():
    cfg = config.load()
    con = ledger.connect()
    now = _now_str()

    positions = []
    for p in ledger.open_positions(con):
        price = market.last_price(p["ticker"])
        positions.append({**p, "now": price,
                          "pl_pct": (price / p["avg_cost"] - 1) * 100 if price else None,
                          "pl_usd": (price - p["avg_cost"]) * p["shares"] if price else None})
    cash = ledger.cash(con)
    equity = cash + sum((p["now"] or p["avg_cost"]) * p["shares"] for p in positions)
    ledger.record_equity(con, equity, cash)
    con.commit()

    import re
    deposited = sum(float(m.group(1)) for (d,) in
                    con.execute("SELECT detail FROM decisions WHERE kind='deposit'")
                    if (m := re.search(r"\$([\d.]+)", d)))
    # deposits are tracked NATIVELY in GBP (meta 'deposited_gbp') — never derived
    # through today's FX rate, so a rate move can't manufacture fake P/L
    dep_meta = ledger.get_meta(con, "deposited_gbp")
    deposited_gbp = float(dep_meta) if dep_meta else deposited * _FX_RATE
    curve = con.execute("SELECT ts, equity FROM equity_history ORDER BY id").fetchall()
    trades_asc = con.execute("SELECT ts,side,ticker,shares,price,value,mode,reason "
                             "FROM trades ORDER BY id").fetchall()
    decisions = con.execute("SELECT ts,kind,detail FROM decisions "
                            "ORDER BY id DESC LIMIT 40").fetchall()
    cand_rows = con.execute("SELECT ts,ticker,score,detail FROM scan_candidates "
                            "ORDER BY id DESC LIMIT 24").fetchall()
    seen, candidates, cand_ts = set(), [], None
    for ts, t, s, d in cand_rows:
        cand_ts = cand_ts or ts
        if t not in seen:
            seen.add(t)
            candidates.append((t, s, json.loads(d)))
    candidates = sorted(candidates[:8], key=lambda c: c[1], reverse=True)
    rewards = con.execute("SELECT signal, COUNT(*), AVG(pnl_pct) FROM signal_rewards "
                          "WHERE contribution > 0.2 GROUP BY signal").fetchall()
    buys_wk = ledger.buys_this_week(con)
    con.close()

    intel = risk.load_intel()
    from bot.signals.reddit import fetch_mentions
    reddit = fetch_mentions()

    from bot.signals.news_feed import collect_headlines
    news_tickers = list(dict.fromkeys(
        [p["ticker"] for p in positions] + [c[0] for c in candidates[:4]]))
    if len(news_tickers) < 4 and reddit:
        # flat/quiet book: keep the headlines panel alive with the loudest radar names
        top_buzz = sorted(reddit.items(), key=lambda kv: kv[1].get("mentions", 0),
                          reverse=True)
        news_tickers += [t for t, _ in top_buzz[:6] if t not in news_tickers]
        news_tickers = news_tickers[:6]
    news = collect_headlines(news_tickers)

    research = risk.load_research()

    # broker truth: refresh (throttled, read-only, no-op without a key) then read
    try:
        from bot import broker_sync
        broker = broker_sync.sync(cfg)
    except Exception:
        broker = {}

    return {
        "cfg": cfg, "now": now, "positions": positions, "cash": cash,
        "equity": equity, "deposited": deposited, "deposited_gbp": deposited_gbp,
        "curve": curve,
        "trades_asc": trades_asc, "closed": _realized_trades(trades_asc),
        "decisions": decisions, "candidates": candidates,
        "cand_ts": _short(cand_ts), "rewards": rewards,
        "buys_wk": buys_wk, "research": research,
        "reddit": reddit, "news": news, "intel": intel, "broker": broker,
    }


# ---------------- charts ----------------

def _equity_svg(curve, deposited, w=640, h=190):
    if not curve:
        return '<div class="mut">no equity history yet</div>'
    pts = [e for _, e in curve]
    if len(pts) == 1:
        pts = pts * 2
    pad, padb = 10, 22
    lo = min(pts + ([deposited] if deposited else []))
    hi = max(pts + ([deposited] if deposited else []))
    if hi - lo < 1:
        lo, hi = lo - 1, hi + 1
    def x(i): return pad + i * (w - 2 * pad) / (len(pts) - 1)
    def y(v): return (h - padb) - (v - lo) * (h - padb - pad) / (hi - lo)
    coords = [(x(i), y(v)) for i, v in enumerate(pts)]
    line = _smooth_path(coords)
    area = line + " L {:.1f},{:.1f} L {:.1f},{:.1f} Z".format(
        coords[-1][0], h - padb, coords[0][0], h - padb)
    color = "#34D399" if (not deposited or pts[-1] >= deposited) else "#F87171"
    grid = "".join('<line x1="{p}" y1="{gy:.1f}" x2="{w2}" y2="{gy:.1f}" '
                   'stroke="#131D30" stroke-width="1"/>'.format(
                       p=pad, w2=w - pad, gy=(h - padb) - k * (h - padb - pad) / 4)
                   for k in range(1, 5))
    dep = ""
    if deposited:
        dep = ('<line x1="{p}" y1="{dy:.1f}" x2="{w2}" y2="{dy:.1f}" stroke="#7E8CA6" '
               'stroke-dasharray="4 4" opacity="0.6"/>').format(
            p=pad, w2=w - pad, dy=y(deposited))
    d0, d1 = curve[0][0][:10], curve[-1][0][:10]
    return ('<svg viewBox="0 0 {w} {h}" width="100%" role="img" aria-label="equity">'
            '<defs><linearGradient id="eq" x1="0" y1="0" x2="0" y2="1">'
            '<stop offset="0%" stop-color="{c}" stop-opacity="0.25"/>'
            '<stop offset="100%" stop-color="{c}" stop-opacity="0"/></linearGradient></defs>'
            '{grid}{dep}<path d="{area}" fill="url(#eq)"/>'
            '<path d="{line}" fill="none" stroke="{c}" stroke-width="2" '
            'stroke-linejoin="round" stroke-linecap="round"/>'
            '<circle cx="{cx:.1f}" cy="{cy:.1f}" r="3.5" fill="{c}"/>'
            '<circle cx="{cx:.1f}" cy="{cy:.1f}" r="6.5" fill="{c}" opacity="0.22"/>'
            '<text x="{p}" y="{h2}" fill="#5A6A87" font-size="9" font-family="Menlo,monospace">{d0}</text>'
            '<text x="{w2}" y="{h2}" fill="#5A6A87" font-size="9" text-anchor="end" font-family="Menlo,monospace">{d1}</text>'
            '<text x="{p}" y="{ty:.1f}" fill="#5A6A87" font-size="9" font-family="Menlo,monospace">${hi:,.0f}</text>'
            '<text x="{p}" y="{by:.1f}" fill="#5A6A87" font-size="9" font-family="Menlo,monospace">${lo:,.0f}</text>'
            '</svg>').format(w=w, h=h, c=color, grid=grid, dep=dep, area=area,
                             line=line, cx=x(len(pts) - 1), cy=y(pts[-1]), p=pad,
                             w2=w - pad, h2=h - 6, d0=d0, d1=d1,
                             ty=y(hi) + 10, by=y(lo) - 3, hi=hi, lo=lo)


def _sparkline(closes, cost=None, w=88, h=26):
    """Tiny inline SVG price line; green if last>=first, red otherwise. If cost
    is given, a faint dashed line marks the entry price."""
    if not closes or len(closes) < 2:
        return '<span class="mut" style="font-size:10px">no data</span>'
    lo, hi = min(closes), max(closes)
    if cost:
        lo, hi = min(lo, cost), max(hi, cost)
    rng = (hi - lo) or 1
    pad = 2
    def x(i): return pad + i * (w - 2 * pad) / (len(closes) - 1)
    def y(v): return (h - pad) - (v - lo) * (h - 2 * pad) / rng
    pts = " ".join("{:.1f},{:.1f}".format(x(i), y(v)) for i, v in enumerate(closes))
    up = closes[-1] >= closes[0]
    color = "#3DDC97" if up else "#FF7A70"
    cost_line = ""
    if cost:
        cost_line = ('<line x1="{p}" y1="{cy:.1f}" x2="{w2}" y2="{cy:.1f}" '
                     'stroke="#5C6B8C" stroke-width="0.7" stroke-dasharray="2 2" '
                     'opacity="0.7"/>').format(p=pad, w2=w - pad, cy=y(cost))
    return ('<svg viewBox="0 0 {w} {h}" width="{w}" height="{h}" '
            'style="vertical-align:middle">{cl}<polyline points="{pts}" fill="none" '
            'stroke="{c}" stroke-width="1.4"/>'
            '<circle cx="{cx:.1f}" cy="{cy:.1f}" r="1.8" fill="{c}"/></svg>').format(
        w=w, h=h, cl=cost_line, pts=pts, c=color, cx=x(len(closes) - 1),
        cy=y(closes[-1]))


def _period_stats(closed):
    """Realized P/L + averages for today / this week / this month."""
    today = dt.date.today()
    monday = today - dt.timedelta(days=today.weekday())
    month1 = today.replace(day=1)
    buckets = {"Day": [], "Week": [], "Month": [], "All time": []}
    for t in closed:
        d = dt.date.fromisoformat(t["ts"][:10])
        buckets["All time"].append(t)
        if d >= month1:
            buckets["Month"].append(t)
        if d >= monday:
            buckets["Week"].append(t)
        if d == today:
            buckets["Day"].append(t)
    rows = []
    for label, ts in buckets.items():
        wins = [t for t in ts if t["pnl"] > 0]
        losses = [t for t in ts if t["pnl"] <= 0]
        net = sum(t["pnl"] for t in ts)
        avg_w = sum(t["pct"] for t in wins) / len(wins) if wins else 0
        avg_l = sum(t["pct"] for t in losses) / len(losses) if losses else 0
        nc = "gain" if net >= 0 else "loss"
        rows.append(
            '<tr><td class="mono">{lb}</td><td class="mono r">{n}</td>'
            '<td class="mono r {nc}">{ns}&#163;{na:,.2f}</td>'
            '<td class="mono r gain">{aw}</td><td class="mono r loss">{al}</td></tr>'.format(
                lb=label, n=len(ts), nc=nc, ns="+" if net >= 0 else "−", na=_gbp(abs(net)),
                aw="+{:.1f}%".format(avg_w) if wins else "—",
                al="{:.1f}%".format(avg_l) if losses else "—"))
    return ('<table><tr><th>Window</th><th class="r">Trades</th><th class="r">Net P/L</th>'
            '<th class="r">Avg win</th><th class="r">Avg loss</th></tr>{}</table>'.format(
                "".join(rows)))


# WSB-flavoured captions, chosen by trade outcome
FAME_CAPS = [
    ("🚀", "TO THE MOON"), ("💎🙌", "diamond hands paid off"),
    ("🤑", "tendies secured"), ("📈", "absolute stonks"),
    ("🧠", "big brain play"), ("🍗", "fat tendies"),
]
SHAME_CAPS = [
    ("💀", "GUH"), ("📉", "bought the top, sold the bottom"),
    ("🧻🙌", "paper hands special"), ("🤡", "clown market got us"),
    ("🎒", "certified bagholder"), ("🔥", "this is fine"),
]


def _hall(closed):
    if not closed:
        return ('<div class="mut">no closed trades yet — the halls await their first '
                'legends and cautionary tales 🫡</div>')
    # Fame = actual winners only; Shame = actual losers only. A trade can never
    # appear in both, and a loss can never render as a green "win".
    winners = [t for t in closed if t["pnl"] > 0]
    losers = [t for t in closed if t["pnl"] < 0]
    best = sorted(winners, key=lambda t: t["pct"], reverse=True)[:3]
    worst = sorted(losers, key=lambda t: t["pct"])[:3]

    def card(t, caps, i):
        emoji, cap = caps[i % len(caps)]
        cls = "gain" if t["pnl"] >= 0 else "loss"   # colour by reality, not by hall
        held = ""
        try:
            held = "{}d".format((dt.date.fromisoformat(t["ts"][:10])
                                 - dt.date.fromisoformat(t["ts"][:10])).days)
        except Exception:
            pass
        return (
            '<div style="border:1px solid var(--line);border-radius:10px;padding:11px 13px;'
            'background:rgba(255,255,255,.02)">'
            '<div style="font-size:20px">{e}</div>'
            '<div class="mono" style="font-size:15px;font-weight:800;margin:3px 0">'
            '<span class="tk" style="color:var(--violet)">{tk}</span> '
            '<span class="{cls}">{ps}{pct:.1f}%</span></div>'
            '<div class="note" style="font-size:11px">{cap}</div>'
            '<div class="mono" style="font-size:10.5px;color:var(--dim);margin-top:3px">'
            '${b:.2f} → ${s:.2f} · {ns}&#163;{amt:,.2f}</div></div>').format(
            e=emoji, tk=t["ticker"], cls=cls, ps="+" if t["pct"] >= 0 else "",
            pct=t["pct"], cap=cap, b=t["buy"], s=t["sell"],
            ns="+" if t["pnl"] >= 0 else "−", amt=_gbp(abs(t["pnl"])))

    empty = '<div class="mut" style="font-size:12px">none yet</div>'
    fame = "".join(card(t, FAME_CAPS, i) for i, t in enumerate(best)) or empty
    shame = "".join(card(t, SHAME_CAPS, i) for i, t in enumerate(worst)) or empty
    grid = ('display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px')
    return (
        '<div class="klabel" style="color:var(--gain)">🏆 Hall of Fame — biggest tendies ({nw} winner{ws})</div>'
        '<div style="{g}">{fame}</div>'
        '<div class="klabel" style="color:var(--loss);margin-top:14px">🤡 Hall of Shame — '
        'lessons in humility ({nl} loser{ls})</div><div style="{g}">{shame}</div>').format(
        g=grid, fame=fame, shame=shame, nw=len(winners), ws="" if len(winners) == 1 else "s",
        nl=len(losers), ls="" if len(losers) == 1 else "s")


def _smooth_path(pts):
    """Catmull-Rom → cubic bezier smoothing for a Robinhood-style curve."""
    if len(pts) < 3:
        return "M " + " L ".join("{:.1f},{:.1f}".format(*p) for p in pts)
    d = "M {:.1f},{:.1f}".format(*pts[0])
    for i in range(len(pts) - 1):
        p0 = pts[i - 1] if i > 0 else pts[0]
        p1, p2 = pts[i], pts[i + 1]
        p3 = pts[i + 2] if i + 2 < len(pts) else p2
        c1x = p1[0] + (p2[0] - p0[0]) / 6.0
        c1y = p1[1] + (p2[1] - p0[1]) / 6.0
        c2x = p2[0] - (p3[0] - p1[0]) / 6.0
        c2y = p2[1] - (p3[1] - p1[1]) / 6.0
        d += " C {:.1f},{:.1f} {:.1f},{:.1f} {:.1f},{:.1f}".format(c1x, c1y, c2x, c2y, p2[0], p2[1])
    return d


def _pnl_line(closed, w=560, h=170):
    """Robinhood-style cumulative realized-P/L curve: thin smoothed line, soft
    gradient fill, baseline at zero, endpoint dot. Replaces the old bar chart."""
    if not closed:
        return '<div class="mut">no closed trades yet — the line starts at your first sale</div>'
    ordered = sorted(closed, key=lambda t: t["ts"])
    cum, running = [0.0], 0.0
    for t in ordered:
        running += t["pnl"]
        cum.append(running)
    lo, hi = min(cum), max(cum)
    if hi - lo < 1:
        lo, hi = lo - 1, hi + 1
    pad_l, pad_r, pad_t, pad_b = 6, 6, 12, 16
    def x(i): return pad_l + i * (w - pad_l - pad_r) / (len(cum) - 1)
    def y(v): return (h - pad_b) - (v - lo) * (h - pad_b - pad_t) / (hi - lo)
    pts = [(x(i), y(v)) for i, v in enumerate(cum)]
    path = _smooth_path(pts)
    end_up = cum[-1] >= 0
    color = "#34D399" if end_up else "#F87171"
    zero_y = y(0)
    area = path + " L {:.1f},{:.1f} L {:.1f},{:.1f} Z".format(pts[-1][0], h - pad_b, pts[0][0], h - pad_b)
    return ('<svg viewBox="0 0 {w} {h}" width="100%" role="img" aria-label="cumulative P/L">'
            '<defs><linearGradient id="pl" x1="0" y1="0" x2="0" y2="1">'
            '<stop offset="0%" stop-color="{c}" stop-opacity="0.22"/>'
            '<stop offset="100%" stop-color="{c}" stop-opacity="0"/></linearGradient></defs>'
            '<line x1="{pl}" y1="{zy:.1f}" x2="{w2}" y2="{zy:.1f}" stroke="#2A3B5C" '
            'stroke-width="1" stroke-dasharray="3 3"/>'
            '<path d="{area}" fill="url(#pl)"/>'
            '<path d="{path}" fill="none" stroke="{c}" stroke-width="2" '
            'stroke-linejoin="round" stroke-linecap="round"/>'
            '<circle cx="{ex:.1f}" cy="{ey:.1f}" r="3.5" fill="{c}"/>'
            '<circle cx="{ex:.1f}" cy="{ey:.1f}" r="6" fill="{c}" opacity="0.25"/>'
            '<text x="{pl}" y="10" fill="#5A6A87" font-size="9" '
            'font-family="Menlo,monospace">cumulative realized P/L</text>'
            '<text x="{w2}" y="{ty:.1f}" fill="{c}" font-size="11" text-anchor="end" '
            'font-weight="700" font-family="Menlo,monospace">{end}</text></svg>').format(
        w=w, h=h, c=color, pl=pad_l, w2=w - pad_r, zy=zero_y, area=area, path=path,
        ex=pts[-1][0], ey=pts[-1][1], ty=max(pts[-1][1] - 8, 20),
        end=("+" if end_up else "−") + "${:,.2f}".format(abs(cum[-1])))


