def _intel_panel(st):
    intel = st.get("intel") or {}
    if not intel or intel.get("_stale"):
        note = ("last intel {} — stale, awaiting next hourly run".format(
            intel.get("generated", "")[:16].replace("T", " ")) if intel.get("_stale")
            else "no hourly intel yet — runs every hour during US market hours")
        return panel("Live intel feed", "hourly", '<div class="mut">{}</div>'.format(note))
    tape = intel.get("tape", "")
    alerts = intel.get("alerts", [])[:12]
    if alerts:
        items = "".join(
            '<div class="alert"><span class="lv {lv}">{lv}</span>'
            '<div class="body"><span class="tk">{tk}</span> {hl}'
            '{link}<div class="sr">{time}</div></div></div>'.format(
                lv=(a.get("level") or "info"), tk=a.get("ticker", ""),
                hl=a.get("headline", ""),
                link=' &middot; <a href="{u}" target="_blank" rel="noopener">source &#8599;</a>'.format(
                    u=a["source"]) if a.get("source", "").startswith("http") else "",
                time=a.get("time", ""))
            for a in alerts)
    else:
        items = '<div class="mut">no material alerts this hour</div>'
    gen = intel.get("generated", "")[:16].replace("T", " ")
    tape_html = ('<div class="note" style="margin-bottom:10px;color:var(--ink)">'
                 '<b style="color:var(--dim)">TAPE:</b> {}</div>'.format(tape)) if tape else ""
    return panel("Live intel feed", "intel " + gen + " UTC", tape_html + items)


WORKFLOW_LABELS = [
    ("trading-scan", "Trading scans"), ("hourly-intel", "Hourly intel"),
    ("daily-research", "Daily research"), ("weekly-review", "Weekly review"),
    ("backtest", "Backtest"),
]


def _fmt_dur(s):
    if s is None:
        return ""
    if s < 60:
        return "{}s".format(s)
    return "{}m {:02d}s".format(s // 60, s % 60)


def _token_panel(st):
    """Claude subscription usage — so you can see what's eating your limits."""
    try:
        from bot.token_log import summary
        day = summary(1)
        week = summary(7)
    except Exception:
        return ""
    if not day and not week:
        return panel("&#129504; Claude usage", "tokens",
                     '<div class="mut">no sessions logged yet — populates as the '
                     'research/intel/learnings jobs run</div>')
    def fmt(n): return "{:,}".format(int(n or 0))
    rows = "".join(
        '<tr><td class="mono">{lb}</td><td class="mono r">{s}</td>'
        '<td class="mono r">{i}</td><td class="mono r">{o}</td></tr>'.format(
            lb=lbl, s=s["sessions"], i=fmt(s["input_tokens"]), o=fmt(s["output_tokens"]))
        for lbl, s in (("Today", day), ("Last 7d", week)))
    by = day.get("by_label", {})
    chips = "".join('<span class="chip">{}: {}</span>'.format(k, v)
                    for k, v in sorted(by.items(), key=lambda x: -x[1]))
    return panel("&#129504; Claude usage", "tokens",
                 '<table><tr><th>Window</th><th class="r">Sessions</th>'
                 '<th class="r">In</th><th class="r">Out</th></tr>{}</table>'
                 '<div class="klabel">Today by job</div><div class="chips">{}</div>'
                 '<div class="note" style="margin-top:6px">Cut usage by lowering job '
                 'frequency (intel/learnings crons). Heavy backtests are Python — '
                 'zero tokens.</div>'.format(rows, chips or '<span class="mut">—</span>'))


def _github_panel(st):
    """Traffic lights only: dot (hover for the run detail), task, next run."""
    health = _load_health()
    runs = health.get("workflows", {})
    rows = []
    for key, label in WORKFLOW_LABELS:
        info = runs.get(key)
        if not info:
            dot, tip = "grey", "not run yet"
        else:
            concl = info.get("conclusion")
            when = info.get("when", "")[5:16].replace("T", " ")
            dur = _fmt_dur(info.get("duration_s"))
            if concl == "success":
                dot, tip = "green", "OK · {} · ran in {}".format(when, dur)
            elif concl in ("skipped", None):
                dot, tip = "grey", "{} · {}".format(concl or "idle", when)
            else:
                dot, tip = "red", "{} · {} · {}".format(concl, when, dur)
        rows.append('<tr><td style="width:14px"><span class="sdot {d}" title="{tip}">'
                    '</span></td>'
                    '<td class="mono" style="white-space:nowrap">{lb}</td>'
                    '<td class="mono mut" style="white-space:nowrap;text-align:right" '
                    'id="nr-{k}">—</td></tr>'.format(d=dot, tip=tip, lb=label, k=key))
    updated = health.get("generated", "")[:16].replace("T", " ")
    return panel("Running on GitHub", "status " + (updated or "—"),
                 '<table><tr><th></th><th>Task</th>'
                 '<th class="r">Next</th></tr>{}</table>'.format("".join(rows)))


